// Extract feedback from Google Chat event
const body = $json.body || $json;
const message = body.message || body;
const sender = message.sender || {};
const space = message.space || {};
const thread = message.thread || {};

const text = (message.text || message.argumentText || '').trim();
const user = sender.displayName || sender.name || 'unknown';
const spaceName = space.name || '';
const threadName = thread.name || '';

// Skip bot messages and empty messages
if (sender.type === 'BOT' || !text) {
  return [{ json: { skip: true, reason: 'Bot message or empty' } }];
}

// Build prompt for PM agent
const prompt = `Classify and process the following user feedback from Google Chat:\n\n**From**: User ${user}\n**Space**: ${spaceName}\n**Message**: ${text}\n\nInstructions:\n1. Classify as: Bug Report, Feature Request, UX Issue, or General Feedback\n2. For Bug Reports: Create a Jira Bug issue with severity assessment\n3. For Feature Requests: Create a Jira Story in the appropriate Epic (CER-7 to CER-14)\n4. For UX Issues: Create a Jira Task with 'needs-ui-work' label\n5. For General Feedback: Log in Confluence under Product Feedback\n\nAlways include the original message text in the Jira description.`;

// Create a timestamp-based key for idempotency
const ts = message.createTime || new Date().toISOString();

return [{ json: {
  skip: false,
  text,
  user,
  space: spaceName,
  prompt,
  idempotencyKey: `feedback:${spaceName}:${ts}`
}}];

